# Instructions ----
#' This file follows the format generated by FIMS:::use_testthat_template().
#' This version mirrors test-integration-fims-estimation-random-effects-without-wrappers.R,
#' but uses the new likelihood components instead of the legacy distribution
#' components.

load(testthat::test_path("fixtures", "integration_test_data.RData"))

iter_id <- 1

verify_fims_likelihood_nll <- function(report,
                                       om_input,
                                       om_output,
                                       em_input) {
  rec_nll <- -sum(dnorm(
    om_input[["logR.resid"]][-1], rep(0, om_input[["nyr"]] - 1),
    om_input[["logR_sd"]], TRUE
  ))

  landings_nll_fleet <- -sum(dlnorm(
    em_input[["L.obs"]][["fleet1"]],
    log(om_output[["L.mt"]][["fleet1"]]),
    sqrt(log(em_input[["cv.L"]][["fleet1"]]^2 + 1)), TRUE
  ))

  index_nll_survey <- -sum(dlnorm(
    em_input[["surveyB.obs"]][["survey1"]],
    log(om_output[["survey_index_biomass"]][["survey1"]]),
    sqrt(log(em_input[["cv.survey"]][["survey1"]]^2 + 1)), TRUE
  ))

  fishing_acomp_observed <- em_input[["L.age.obs"]][["fleet1"]]
  fishing_acomp_expected <- om_output[["L.age"]][["fleet1"]] /
    rowSums(om_output[["L.age"]][["fleet1"]])
  survey_acomp_observed <- em_input[["survey.age.obs"]][["survey1"]]
  survey_acomp_expected <- om_output[["survey_age_comp"]][["survey1"]] /
    rowSums(om_output[["survey_age_comp"]][["survey1"]])
  age_comp_nll_fleet <- age_comp_nll_survey <- 0
  for (y in 1:om_input[["nyr"]]) {
    age_comp_nll_fleet <- age_comp_nll_fleet -
      FIMS_dmultinom(
        fishing_acomp_observed[y, ] * em_input[["n.L"]][["fleet1"]],
        fishing_acomp_expected[y, ]
      )
    age_comp_nll_survey <- age_comp_nll_survey -
      FIMS_dmultinom(
        survey_acomp_observed[y, ] * em_input[["n.survey"]][["survey1"]],
        survey_acomp_expected[y, ]
      )
  }

  fishing_lengthcomp_observed <- em_input[["L.length.obs"]][["fleet1"]]
  fishing_lengthcomp_expected <- om_output[["L.length"]][["fleet1"]] /
    rowSums(om_output[["L.length"]][["fleet1"]])
  survey_lengthcomp_observed <- em_input[["survey.length.obs"]][["survey1"]]
  survey_lengthcomp_expected <- om_output[["survey_length_comp"]][["survey1"]] /
    rowSums(om_output[["survey_length_comp"]][["survey1"]])
  lengthcomp_nll_fleet <- lengthcomp_nll_survey <- 0
  for (y in 1:om_input[["nyr"]]) {
    lengthcomp_nll_fleet <- lengthcomp_nll_fleet -
      FIMS_dmultinom(
        fishing_lengthcomp_observed[y, ] * em_input[["n.L.lengthcomp"]][["fleet1"]],
        fishing_lengthcomp_expected[y, ]
      )
    lengthcomp_nll_survey <- lengthcomp_nll_survey -
      FIMS_dmultinom(
        survey_lengthcomp_observed[y, ] * em_input[["n.survey.lengthcomp"]][["survey1"]],
        survey_lengthcomp_expected[y, ]
      )
  }

  expected_nll <- c(
    landings_nll_fleet,
    age_comp_nll_fleet,
    lengthcomp_nll_fleet,
    index_nll_survey,
    age_comp_nll_survey,
    lengthcomp_nll_survey,
    rec_nll
  )

  #' @description Test that the likelihood-component NLL vector has the expected length.
  expect_length(report[["nll_components"]], length(expected_nll))
  #' @description Test that likelihood-component NLLs equal expected values.
  expect_equal(report[["nll_components"]], expected_nll)
  #' @description Test that the total jnll equals the sum of expected likelihood components.
  expect_equal(report[["jnll"]], sum(expected_nll))
}

result <- setup_and_run_FIMS_without_wrappers(
  iter_id = iter_id,
  om_input_list = om_input_list,
  om_output_list = om_output_list,
  em_input_list = em_input_list,
  estimation_mode = FALSE,
  random_effects = c(recruitment = "log_devs"),
  use_likelihood_components = TRUE
)

test_that("deterministic run works with correct inputs using likelihood components", {
  #' @description Test that the output from FIMS run matches the model comparison project OM values.
  verify_fims_deterministic(
    report = result[["report"]],
    estimates = result[["sdr_fixed"]],
    om_input = om_input_list[[iter_id]],
    om_output = om_output_list[[iter_id]],
    em_input = em_input_list[[iter_id]],
    use_fimsfit = FALSE
  )
})

test_that("deterministic run returns correct likelihood-component nlls", {
  #' @description Test that the likelihood-component NLLs from FIMS match the expected values.
  verify_fims_likelihood_nll(
    report = result[["report"]],
    om_input = om_input_list[[iter_id]],
    om_output = om_output_list[[iter_id]],
    em_input = em_input_list[[iter_id]]
  )
})

test_that("deterministic run returns correct number of parameters and random effects using likelihood components", {
  #' @description Test that the number of parameters are correct.
  expect_equal(length(result[["obj"]][["par"]]), 48)
  #' @description Test that the number of random effects are correct.
  expect_equal(length(result[["obj"]][["env"]][["random"]]), 29)
})

